import{c as a,Q as e,j as n,m as t}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Anatomy of the .claude/ folder — @akshay_pachaar","description":"","frontmatter":{"title":"Anatomy of the .claude/ folder — @akshay_pachaar","author":"Akshay 🚀（@akshay_pachaar）","date":"2026-03-21T00:00:00.000Z","source":"https://x.com/akshay_pachaar/status/2035341800739877091","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-03-21-@akshay_pachaar-877091.md","filePath":"research/tweets/2026-03-21-@akshay_pachaar-877091.md","lastUpdated":1779894392000}'),i={name:"research/tweets/2026-03-21-@akshay_pachaar-877091.md"};function o(l,s,r,p,h,d){return e(),n("div",null,[...s[0]||(s[0]=[t(`<h1 id="anatomy-of-the-claude-folder-—-akshay-pachaar" tabindex="-1">Anatomy of the .claude/ folder — @akshay_pachaar <a class="header-anchor" href="#anatomy-of-the-claude-folder-—-akshay-pachaar" aria-label="Permalink to &quot;Anatomy of the .claude/ folder — @akshay_pachaar&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/akshay_pachaar/status/2035341800739877091" target="_blank" rel="noreferrer">https://x.com/akshay_pachaar/status/2035341800739877091</a><strong>作者</strong>：Akshay 🚀（@akshay_pachaar） <strong>發布日期</strong>：2026-03-21 <strong>收錄日期</strong>：2026-04-26 <strong>類型</strong>：Twitter Article <strong>統計</strong>：11328 likes · 1452 retweets · 43211 bookmarks · 11077074 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p><strong>A complete guide to CLAUDE.md, custom commands, skills, agents, and permissions, and how to set them up properly.</strong></p><p>Most Claude Code users treat the <strong>.claude folder</strong> like a black box. They know it exists. They&#39;ve seen it appear in their project root. But they&#39;ve never opened it, let alone understood what every file inside it does.</p><p>That&#39;s a missed opportunity.</p><p><strong>The .claude folder is the control center for how Claude behaves in your project. It holds your instructions, your custom commands, your permission rules, and even Claude&#39;s memory across sessions. Once you understand what lives where and why, you can configure Claude Code to behave exactly the way your team needs it to.</strong></p><p>This guide walks through the entire anatomy of the folder, from the files you&#39;ll use daily to the ones you&#39;ll set once and forget.</p><h2 id="two-folders-not-one" tabindex="-1">Two folders, not one <a class="header-anchor" href="#two-folders-not-one" aria-label="Permalink to &quot;Two folders, not one&quot;">​</a></h2><p>Before diving in, one thing worth knowing upfront: there are actually two .claude directories, not one.</p><p>The first lives inside your project and the second lives in your home directory.</p><p><strong>The project-level folder holds team configuration. You commit it to git. Everyone on the team gets the same rules, the same custom commands, the same permission policies.</strong></p><p>The <strong>global ~/.claude/</strong> folder holds your personal preferences and machine-local state like session history and auto-memory.</p><h2 id="claude-md-claude-s-instruction-manual" tabindex="-1">CLAUDE.md: Claude&#39;s instruction manual <a class="header-anchor" href="#claude-md-claude-s-instruction-manual" aria-label="Permalink to &quot;CLAUDE.md: Claude&#39;s instruction manual&quot;">​</a></h2><p>This is the most important file in the entire system. When you start a Claude Code session, the first thing it reads is CLAUDE.md. It loads it straight into the system prompt and keeps it in mind for the entire <strong>conversation</strong>.</p><p>Simply put: <strong>whatever you write in CLAUDE.md, Claude will follow.</strong></p><p>If you tell Claude to always write tests before implementation, it will. If you say &quot;never use console.log for error handling, always use the custom logger module,&quot; it will respect that every time.</p><p>A <strong>CLAUDE.md</strong> at your project root is the most common setup. But you can also have one in ~/.claude/CLAUDE.md for global preferences that apply across all projects, and even one inside subdirectories for folder-specific rules. Claude reads all of them and combines them.</p><h3 id="what-actually-belongs-in-claude-md" tabindex="-1">What actually belongs in CLAUDE.md <a class="header-anchor" href="#what-actually-belongs-in-claude-md" aria-label="Permalink to &quot;What actually belongs in CLAUDE.md&quot;">​</a></h3><p>Most people either write too much or too little. Here&#39;s what works.</p><h4 id="write" tabindex="-1">Write: <a class="header-anchor" href="#write" aria-label="Permalink to &quot;Write:&quot;">​</a></h4><ul><li>Build, test, and lint commands (npm run test, make build, etc.)</li><li>Key architectural decisions (&quot;we use a monorepo with Turborepo&quot;)</li><li>Non-obvious gotchas (&quot;TypeScript strict mode is on, unused variables are errors&quot;)</li><li>Import conventions, naming patterns, error handling styles</li><li>File and folder structure for the main modules</li></ul><h4 id="don-t-write" tabindex="-1">Don&#39;t write: <a class="header-anchor" href="#don-t-write" aria-label="Permalink to &quot;Don&#39;t write:&quot;">​</a></h4><ul><li>Anything that belongs in a linter or formatter config</li><li>Full documentation you can already link to</li><li>Long paragraphs explaining theory</li></ul><p>Keep CLAUDE.md under 200 lines. Files longer than that start eating too much context, and Claude&#39;s instruction adherence actually drops.</p><p>Here&#39;s a minimal but effective example:</p><div class="language-plaintext vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plaintext</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># Project: Acme API</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Commands</span></span>
<span class="line"><span>npm run dev          # Start dev server</span></span>
<span class="line"><span>npm run test         # Run tests (Jest)</span></span>
<span class="line"><span>npm run lint         # ESLint + Prettier check</span></span>
<span class="line"><span>npm run build        # Production build</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Architecture</span></span>
<span class="line"><span>- Express REST API, Node 20</span></span>
<span class="line"><span>- PostgreSQL via Prisma ORM</span></span>
<span class="line"><span>- All handlers live in src/handlers/</span></span>
<span class="line"><span>- Shared types in src/types/</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Conventions</span></span>
<span class="line"><span>- Use zod for request validation in every handler</span></span>
<span class="line"><span>- Return shape is always { data, error }</span></span>
<span class="line"><span>- Never expose stack traces to the client</span></span>
<span class="line"><span>- Use the logger module, not console.log</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Watch out for</span></span>
<span class="line"><span>- Tests use a real local DB, not mocks. Run \`npm run db:test:reset\` first</span></span>
<span class="line"><span>- Strict TypeScript: no unused imports, ever</span></span></code></pre></div><p>That&#39;s ~20 lines. It gives Claude everything it needs to work productively in this codebase without constant clarification.</p><h2 id="claude-local-md-for-personal-overrides" tabindex="-1">CLAUDE.local.md for personal overrides <a class="header-anchor" href="#claude-local-md-for-personal-overrides" aria-label="Permalink to &quot;CLAUDE.local.md for personal overrides&quot;">​</a></h2><p>Sometimes you have a preference that&#39;s specific to you, not the whole team. Maybe you prefer a different test runner, or you want Claude to always open files using a specific pattern.</p><p>Create CLAUDE.local.md in your project root. Claude reads it alongside the main CLAUDE.md, and it&#39;s automatically gitignored so your personal tweaks never land in the repo.</p><h2 id="the-rules-folder-modular-instructions-that-scale" tabindex="-1">The rules/ folder: modular instructions that scale <a class="header-anchor" href="#the-rules-folder-modular-instructions-that-scale" aria-label="Permalink to &quot;The rules/ folder: modular instructions that scale&quot;">​</a></h2><p>CLAUDE.md works great for a single project. But once your team grows, you end up with a 300-line CLAUDE.md that nobody maintains and everyone ignores.</p><p>The rules/ folder solves that.</p><p><strong>Every markdown file inside .claude/rules/ gets loaded alongside your CLAUDE.md automatically. Instead of one giant file, you split instructions by concern:</strong></p><div class="language-plaintext vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plaintext</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.claude/rules/</span></span>
<span class="line"><span>├── code-style.md</span></span>
<span class="line"><span>├── testing.md</span></span>
<span class="line"><span>├── api-conventions.md</span></span>
<span class="line"><span>└── security.md</span></span></code></pre></div><p>Each file stays focused and easy to update. The team member who owns API conventions edits api-conventions.md. The person who owns testing standards edits testing.md. Nobody stomps on each other.</p><p>The real power comes from <strong>path-scoped rules</strong>. Add a YAML frontmatter block to a rule file and it only activates when Claude is working with matching files:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">paths</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;src/api/**/*.ts&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;src/handlers/**/*.ts&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># API Design Rules</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> All handlers return { data, error } shape</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Use zod for request body validation</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Never expose internal error details to clients</span></span></code></pre></div><p>Claude won&#39;t load this file when it&#39;s editing a React component. It only loads when it&#39;s working inside src/api/ or src/handlers/. Rules without a paths field load unconditionally, every session.</p><p>This is the right pattern once your CLAUDE.md starts feeling crowded.</p><h2 id="the-hooks-system-deterministic-control-over-claude-s-behavior" tabindex="-1">The hooks system: deterministic control over Claude&#39;s behavior <a class="header-anchor" href="#the-hooks-system-deterministic-control-over-claude-s-behavior" aria-label="Permalink to &quot;The hooks system: deterministic control over Claude&#39;s behavior&quot;">​</a></h2><p>CLAUDE.md instructions are good. But they&#39;re suggestions. Claude follows them most of the time, not all of the time. You can&#39;t rely on a language model to always run your linter, never execute a dangerous command, or consistently notify you when it&#39;s done.</p><p>Hooks make these behaviors deterministic. They&#39;re event handlers that fire automatically at specific points in Claude&#39;s workflow. Your shell script runs every time, no exceptions.</p><div class="language-plaintext vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plaintext</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.claude/</span></span>
<span class="line"><span>├── settings.json              # hooks config lives here, under the &quot;hooks&quot; key</span></span>
<span class="line"><span>└── hooks/                     # your hook scripts (convention, not required)</span></span>
<span class="line"><span>    ├── bash-firewall.sh       # PreToolUse: blocks dangerous commands</span></span>
<span class="line"><span>    ├── auto-format.sh         # PostToolUse: runs formatter on edited files</span></span>
<span class="line"><span>    └── enforce-tests.sh       # Stop: ensures tests pass before finishing</span></span></code></pre></div><p>All hook configuration lives in settings.json under a hooks key. Claude Code snapshots the config at session start, receives a JSON payload on stdin when an event fires, and uses exit codes to decide what happens next. The critical thing to know: <strong>exit code 2</strong> is the only code that blocks execution. Exit 0 means success. Exit 1 means error but non-blocking. Exit 2 means stop everything and send your stderr to Claude for self-correction. Using exit 1 for security hooks is the most common mistake. It logs an error and does nothing.</p><p>The events you&#39;ll use most: <strong>PreToolUse</strong> (fires before any tool runs, your security gate), <strong>PostToolUse</strong> (fires after a tool succeeds, for formatters and linters), <strong>Stop</strong> (fires when Claude finishes, for quality gates like &quot;tests must pass&quot;), <strong>UserPromptSubmit</strong> (fires when you press enter, for prompt validation), <strong>Notification</strong> (for desktop alerts), and <strong>SessionStart/SessionEnd</strong> (for context injection and cleanup). For tool events, a matcher regex field narrows which tools trigger the hook. &quot;Write|Edit|MultiEdit&quot; targets file changes. &quot;Bash&quot; targets shell commands. Omitting it matches everything.</p><p>Here&#39;s what a typical hooks config looks like. This auto-formats every file Claude touches and blocks dangerous bash commands:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;hooks&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;PostToolUse&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;matcher&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Write|Edit|MultiEdit&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;hooks&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">          {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">            &quot;type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">            &quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;jq -r &#39;.tool_input.file_path&#39; | xargs npx prettier --write 2&gt;/dev/null&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">          }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;PreToolUse&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;matcher&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Bash&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;hooks&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">          { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;$CLAUDE_PROJECT_DIR/.claude/hooks/bash-firewall.sh&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>The bash firewall script reads the command from stdin, checks it against dangerous patterns like rm -rf /, git push --force main, and DROP TABLE, and exits with code 2 to block anything that matches.</p><p>Stop hooks are equally powerful. A script that runs npm test and exits with code 2 on failure will prevent Claude from declaring &quot;done&quot; until the suite is green. One gotcha: always check the <strong>stop_hook_active</strong> flag in the JSON payload. Without it, the hook blocks Claude, Claude retries, the hook blocks again, and you get an infinite loop. Let Claude stop on the second attempt.</p><p>For desktop notifications, a Notification hook with osascript (macOS) or notify-send (Linux) wired up in ~/.claude/settings.json works across all projects.</p><p>A few things to watch out for. Hooks don&#39;t hot-reload mid-session. PostToolUse can&#39;t undo anything since the tool already ran, so use PreToolUse if you need to prevent an action. Hooks fire recursively for subagent actions too. And hooks execute with your full user permissions and no sandboxing, so always quote shell variables, validate JSON input, and use absolute paths for script references.</p><h2 id="the-skills-folder-reusable-workflows-on-demand" tabindex="-1">The skills/ folder: reusable workflows on demand <a class="header-anchor" href="#the-skills-folder-reusable-workflows-on-demand" aria-label="Permalink to &quot;The skills/ folder: reusable workflows on demand&quot;">​</a></h2><p><strong>Skills are workflows that Claude can invoke on its own, based on the context, when the task matches the skill&#39;s description. Skills watch the conversation and act when the moment is right.</strong></p><p>Each skill lives in its own subdirectory with a SKILL.md file:</p><div class="language-plaintext vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plaintext</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.claude/skills/</span></span>
<span class="line"><span>├── security-review/</span></span>
<span class="line"><span>│   ├── SKILL.md</span></span>
<span class="line"><span>│   └── DETAILED_GUIDE.md</span></span>
<span class="line"><span>└── deploy/</span></span>
<span class="line"><span>    ├── SKILL.md</span></span>
<span class="line"><span>    └── templates/</span></span>
<span class="line"><span>        └── release-notes.md</span></span></code></pre></div><p>The SKILL.md uses YAML frontmatter to describe when to use it:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">security-review</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Comprehensive security audit. Use when reviewing code for</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  vulnerabilities, before deployments, or when the user mentions security.</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">allowed-tools</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Read, Grep, Glob</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Analyze the codebase for security vulnerabilities:</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">1.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> SQL injection and XSS risks</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">2.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Exposed credentials or secrets</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">3.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Insecure configurations</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">4.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Authentication and authorization gaps</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Report findings with severity ratings and specific remediation steps.</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Reference @DETAILED_GUIDE.md for our security standards.</span></span></code></pre></div><p>When you say &quot;review this PR for security issues,&quot; Claude reads the description, recognizes it matches, and invokes the skill automatically. You can also call it explicitly with <strong>/security-review</strong>.</p><p><strong>The key difference from commands: skills can bundle supporting files alongside them.</strong> The @DETAILED_GUIDE.md reference above pulls in a detailed document that lives right next to SKILL.md. Commands are single files. Skills are packages.</p><p><strong>Personal skills</strong> go in ~/.claude/skills/ and are available across all your projects.</p><h2 id="the-agents-folder-specialized-subagent-personas" tabindex="-1">The agents/ folder: specialized subagent personas <a class="header-anchor" href="#the-agents-folder-specialized-subagent-personas" aria-label="Permalink to &quot;The agents/ folder: specialized subagent personas&quot;">​</a></h2><p>When a task is complex enough to benefit from a dedicated specialist, you can define a subagent persona in .claude/agents/. Each agent is a markdown file with its own system prompt, tool access, and model preference:</p><div class="language-plaintext vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plaintext</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.claude/agents/</span></span>
<span class="line"><span>├── code-reviewer.md</span></span>
<span class="line"><span>└── security-auditor.md</span></span></code></pre></div><p>Here&#39;s what a code-reviewer.md looks like:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">code-reviewer</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Expert code reviewer. Use PROACTIVELY when reviewing PRs,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  checking for bugs, or validating implementations before merging.</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">model</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">sonnet</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">tools</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Read, Grep, Glob</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">You are a senior code reviewer with a focus on correctness and maintainability.</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">When reviewing code:</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Flag bugs, not just style issues</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Suggest specific fixes, not vague improvements</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Check for edge cases and error handling gaps</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Note performance concerns only when they matter at scale</span></span></code></pre></div><p>When Claude needs a code review done, it spawns this agent in its own isolated context window. The agent does its work, compresses the findings, and reports back. Your main session doesn&#39;t get cluttered with thousands of tokens of intermediate exploration.</p><p>The tools field restricts what the agent can do. A security auditor only needs Read, Grep, and Glob. It has no business writing files. That restriction is intentional and worth being explicit about.</p><p>The model field lets you use a cheaper, faster model for focused tasks. Haiku handles most read-only exploration well. Save Sonnet and Opus for the work that actually needs them.</p><p><strong>Personal agents</strong> go in ~/.claude/agents/ and are available across all projects.</p><h2 id="settings-json-permissions-and-project-config" tabindex="-1">settings.json: permissions and project config <a class="header-anchor" href="#settings-json-permissions-and-project-config" aria-label="Permalink to &quot;settings.json: permissions and project config&quot;">​</a></h2><p>The <strong>settings.json</strong> file inside .claude/ controls what Claude is and <strong>isn&#39;t</strong> allowed to do. This is also where your hooks live and it&#39;s where you define which tools Claude can run, which files it can read, and whether it needs to ask before running certain commands.</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;$schema&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://json.schemastore.org/claude-code-settings.json&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;permissions&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;allow&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Bash(npm run *)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Bash(git status)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Bash(git diff *)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Read&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Write&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Edit&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;deny&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Bash(rm -rf *)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Bash(curl *)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Read(./.env)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Read(./.env.*)&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="here-s-what-each-part-does" tabindex="-1">Here&#39;s what each part does. <a class="header-anchor" href="#here-s-what-each-part-does" aria-label="Permalink to &quot;Here&#39;s what each part does.&quot;">​</a></h3><p><strong>The $schema line</strong> enables autocomplete and inline validation in VS Code or Cursor. Always include it.</p><p><strong>The allow list</strong> contains commands that run without Claude asking for confirmation. For most projects, a good allow list covers:</p><ul><li>Bash(npm run *) or Bash(make *) so Claude can run your scripts freely</li><li>Bash(git *) for read-only git commands</li><li>Read, Write, Edit, Glob, Grep for file operations</li></ul><p><strong>The deny list</strong> contains commands that are blocked entirely, no matter what. A sensible deny list blocks:</p><ul><li>Destructive shell commands like rm -rf</li><li>Direct network commands like curl</li><li>Sensitive files like .env and anything in secrets/</li></ul><p><strong>If something isn&#39;t in either list, Claude asks before proceeding. That middle ground is intentional. It gives you a safety net without having to anticipate every possible command upfront.</strong></p><h3 id="settings-local-json-for-personal-overrides" tabindex="-1"><strong>settings.local.json for personal overrides</strong> <a class="header-anchor" href="#settings-local-json-for-personal-overrides" aria-label="Permalink to &quot;**settings.local.json for personal overrides**&quot;">​</a></h3><p>Same idea as CLAUDE.local.md. Create .claude/<strong>settings.local.json</strong> for permission changes you don&#39;t want committed. It&#39;s auto-gitignored.</p><h2 id="the-global-claude-folder" tabindex="-1">The global ~/.claude/ folder <a class="header-anchor" href="#the-global-claude-folder" aria-label="Permalink to &quot;The global ~/.claude/ folder&quot;">​</a></h2><p>You don&#39;t interact with this folder often, but it&#39;s useful to know what&#39;s in it.</p><p><strong>~/.claude/CLAUDE.md</strong> loads into every Claude Code session, across all your projects. Good place for your personal coding principles, preferred style, or anything you want Claude to remember regardless of which repo you&#39;re in.</p><p><strong>~/.claude/projects/</strong> stores session transcripts and auto-memory per project. Claude Code automatically saves notes to itself as it works: commands it discovers, patterns it observes, architecture insights. These persist across sessions. You can browse and edit them with /memory.</p><p><strong>~/.claude/commands/</strong> and <strong>~/.claude/skills/</strong> hold personal commands and skills available across all projects.</p><p>You generally don&#39;t need to manually manage these. But knowing they exist is handy when Claude seems to &quot;remember&quot; something you never told it, or when you want to wipe a project&#39;s auto-memory and start fresh.</p><h3 id="the-full-picture" tabindex="-1">The full picture <a class="header-anchor" href="#the-full-picture" aria-label="Permalink to &quot;The full picture&quot;">​</a></h3><p>Here&#39;s how everything comes together:</p><div class="language-plaintext vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plaintext</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>your-project/</span></span>
<span class="line"><span>├── CLAUDE.md                  # Team instructions (committed)</span></span>
<span class="line"><span>├── CLAUDE.local.md            # Your personal overrides (gitignored)</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>└── .claude/</span></span>
<span class="line"><span>    ├── settings.json          # Permissions, hooks, config (committed)</span></span>
<span class="line"><span>    ├── settings.local.json    # Personal permission overrides (gitignored)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── hooks/                 # Hook scripts referenced by settings.json</span></span>
<span class="line"><span>    │   ├── bash-firewall.sh   # PreToolUse: block dangerous commands</span></span>
<span class="line"><span>    │   ├── auto-format.sh     # PostToolUse: format files after edits</span></span>
<span class="line"><span>    │   └── enforce-tests.sh   # Stop: ensure tests pass before finishing</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── rules/                 # Modular instruction files</span></span>
<span class="line"><span>    │   ├── code-style.md</span></span>
<span class="line"><span>    │   ├── testing.md</span></span>
<span class="line"><span>    │   └── api-conventions.md</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── skills/                # Auto-invoked workflows</span></span>
<span class="line"><span>    │   ├── security-review/</span></span>
<span class="line"><span>    │   │   └── SKILL.md</span></span>
<span class="line"><span>    │   └── deploy/</span></span>
<span class="line"><span>    │       └── SKILL.md</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    └── agents/                # Specialized subagent personas</span></span>
<span class="line"><span>        ├── code-reviewer.md</span></span>
<span class="line"><span>        └── security-auditor.md</span></span>
<span class="line"><span></span></span>
<span class="line"><span>~/.claude/</span></span>
<span class="line"><span>├── CLAUDE.md                  # Your global instructions</span></span>
<span class="line"><span>├── settings.json              # Your global settings + hooks</span></span>
<span class="line"><span>├── skills/                    # Your personal skills (all projects)</span></span>
<span class="line"><span>├── agents/                    # Your personal agents (all projects)</span></span>
<span class="line"><span>└── projects/                  # Session history + auto-memory</span></span></code></pre></div><h2 id="a-practical-setup-to-get-started" tabindex="-1">A practical setup to get started <a class="header-anchor" href="#a-practical-setup-to-get-started" aria-label="Permalink to &quot;A practical setup to get started&quot;">​</a></h2><p>If you&#39;re starting from scratch, here&#39;s a progression that works well.</p><p><strong>Step 1.</strong> Run /init inside Claude Code. It generates a starter CLAUDE.md by reading your project. Edit it down to the essentials.</p><p><strong>Step 2.</strong> Add .claude/settings.json with allow/deny rules appropriate for your stack. At minimum, allow your run commands and deny .env reads.</p><p><strong>Step 3.</strong> Create one or two commands for the workflows you do most. Code review and issue fixing are good starting points.</p><p><strong>Step 4.</strong> As your project grows and your CLAUDE.md gets crowded, start splitting instructions into .claude/rules/ files. Scope them by path where it makes sense.</p><p><strong>Step 5.</strong> Add a ~/.claude/CLAUDE.md with your personal preferences. This might be something like &quot;always write types before implementations&quot; or &quot;prefer functional patterns over class-based.&quot;</p><p>That&#39;s genuinely all you need for 95% of projects. Skills and agents come in when you have recurring complex workflows worth packaging up.</p><h3 id="the-key-insight" tabindex="-1">The key insight <a class="header-anchor" href="#the-key-insight" aria-label="Permalink to &quot;The key insight&quot;">​</a></h3><p>The <strong>.claude folder</strong> is really a protocol for telling Claude who you are, what your project does, and what rules it should follow. The more clearly you define that, the less time you spend correcting Claude and the more time it spends doing useful work.</p><p><strong>CLAUDE.md is your highest-leverage file. Get that right first. Everything else is optimization.</strong></p><p>Start small, refine as you go, and treat it like any other piece of infrastructure in your project: something that pays dividends every day once it&#39;s set up properly.</p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：完整解剖 .claude/ 資料夾結構，涵蓋 CLAUDE.md、rules/、hooks、skills、agents、settings.json 的用途與最佳實踐。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ol><li>.claude/ 有兩層：專案級（提交 git、團隊共享）與全域 ~/.claude/（個人偏好、跨專案）</li><li>CLAUDE.md 是最高槓桿檔案，建議 200 行以內，避免 context 被吃掉導致指令遵從率下降</li><li>rules/ 資料夾解決 CLAUDE.md 過長問題，支援 YAML frontmatter 的 path-scoped 條件載入</li><li>Hooks 提供確定性控制：exit code 2 才能阻斷執行，常見錯誤是用 exit 1（非阻斷）做安全閘道</li><li>Skills（可帶附屬檔案的自動觸發工作流）vs Commands（單一檔案）vs Agents（隔離 context 的專屬子代理人）三者明確分工</li></ol><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>CLAUDE.md 建議上限：200 行（超過則指令遵從率下降）</li><li>exit code 2：唯一能阻斷 Claude 工具執行的 exit code</li><li>stop_hook_active flag：Stop hook 必須檢查此旗標，否則觸發無限迴圈</li><li>模型分層：Haiku 處理唯讀探索，Sonnet/Opus 留給需要深度推理的任務</li><li>5 步驟入門：/init → settings.json → commands → rules/ 拆分 → ~/.claude/CLAUDE.md</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ol><li>文章對 Skills 與 Agents 的邊界說明偏簡略（「Skills 是套件，Commands 是單一檔案」），但未給出何時用 Skill 、何時用 Agent 的明確判斷準則——本 workspace 的 subagent-strategy.md 補充了更清楚的決策樹。</li><li>200 行 CLAUDE.md 上限是實用建議，但未說明依據（context token 消耗還是注意力稀釋）；本 workspace 的 context-management.md 有更精確的 300-400k token rot 閾值數據。</li><li>hooks 的 stop_hook_active 防無限迴圈說明是少見的實戰 gotcha，對 workspace 的 auto-sync.md hook 設計具有直接參考價值。</li></ol><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>8/10</td><td>hooks 出口碼規則、path-scoped rules、stop_hook_active 均可直接對應到 auto-sync.md 與 settings.json</td></tr><tr><td>B. 創新性 (20%)</td><td>5/10</td><td>內容與官方文件高度重疊，對已熟悉 .claude/ 架構的用戶新鮮感有限</td></tr><tr><td>C. 證據品質 (20%)</td><td>6/10</td><td>有具體範例與程式碼片段，但多為示範性而非實測數據；200 行上限缺乏來源</td></tr><tr><td>D. 技術深度 (15%)</td><td>7/10</td><td>hooks exit code 機制、path-scoped rules、stop_hook_active 等細節達工程師可直接參照的水準</td></tr><tr><td>E. 泛化性 (15%)</td><td>8/10</td><td>適用任何使用 Claude Code 的專案與團隊，不依賴特定技術棧</td></tr><tr><td><strong>加權總分</strong></td><td><strong>6.8/10</strong></td><td>8×0.3+5×0.2+6×0.2+7×0.15+8×0.15</td></tr></tbody></table><p><strong>整合決策</strong>：Rule <strong>理由</strong>：hooks exit code 規約（exit 2 才阻斷、stop_hook_active 防迴圈）與 path-scoped rules 用法可補充進 auto-sync.md 的 Known Gotchas，強化現有規則說明。</p>`,118)])])}const k=a(i,[["render",o]]);export{u as __pageData,k as default};
